SELECT

FROM error_logs
WHERE 1 = 1


  AND (
  LOWER(COALESCE(message, '')) LIKE LOWER(CONCAT('%', #{keyword}, '%'))
  OR LOWER(COALESCE(error_code, '')) LIKE LOWER(CONCAT('%', #{keyword}, '%'))
  OR LOWER(COALESCE(operation_type, '')) LIKE LOWER(CONCAT('%', #{keyword}, '%'))
  OR LOWER(COALESCE(request_id, '')) LIKE LOWER(CONCAT('%', #{keyword}, '%'))
  )



  AND error_code = #{errorCode}



  AND severity = #{severity}



  AND status = #{status}



  AND operation_type = #{operationType}



  AND company_id = #{companyId}



  AND actor_role ILIKE CONCAT('%', #{actorRole}, '%')



  AND created_at >= CAST(#{startDate} AS timestamptz)



  AND created_at < CAST(#{endDate} AS timestamptz) + INTERVAL '1 day'


ORDER BY created_at DESC
LIMIT #{limit}
OFFSET #{offset}

SELECT COUNT(*)
FROM error_logs
WHERE 1 = 1


  AND (
  LOWER(COALESCE(message, '')) LIKE LOWER(CONCAT('%', #{keyword}, '%'))
  OR LOWER(COALESCE(error_code, '')) LIKE LOWER(CONCAT('%', #{keyword}, '%'))
  OR LOWER(COALESCE(operation_type, '')) LIKE LOWER(CONCAT('%', #{keyword}, '%'))
  OR LOWER(COALESCE(request_id, '')) LIKE LOWER(CONCAT('%', #{keyword}, '%'))
  )



  AND error_code = #{errorCode}



  AND severity = #{severity}



  AND status = #{status}



  AND operation_type = #{operationType}



  AND company_id = #{companyId}



  AND actor_role ILIKE CONCAT('%', #{actorRole}, '%')



  AND created_at >= CAST(#{startDate} AS timestamptz)



  AND created_at < CAST(#{endDate} AS timestamptz) + INTERVAL '1 day'
